    // where nums[i] is greater than the previous element (i.e., the last transition was '<').
    // The sequence ends with an increasing step or is of length 1.
    const dp_up = new Array(n).fill(0);

    // dp_down[i]: maximum score of a valid subsequence ending at index i, 
    // where nums[i] is smaller than the previous element (i.e., the last transition was '>').
    // The sequence ends with a decreasing step or is of length 1.
